// ---------------- Antd Icon 封装 ----------------
interface AppIconProps extends Omit<React.ComponentProps<typeof Icon>, 'component'> {
  name: SvgIconName;
}

const AppIcon: React.FC<AppIconProps> = ({ name, ...rest }) => {
  const SvgComponent = SvgIcons[name];
  if (!SvgComponent) return null;
  return <Icon component={SvgComponent} {...rest} />;
};

